spec.setup_code:
return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var duration = 12000;
    var progress = (t % duration) / duration;

    var stage = 1;
    if (progress >= 0.25 && progress < 0.50) stage = 2;
    else if (progress >= 0.50 && progress < 0.75) stage = 3;
    else if (progress >= 0.75) stage = 4;

    var midY = H / 2 - 35;
    var midX = W / 2;
    var radius = 6;

    // Helper to draw a grid of circles
    function drawGrid(count, color) {
      ctx.fillStyle = color;
      // Arrange in grid depending on count
      if (count === 2) {
        // 1 row of 2
        ctx.beginPath();
        ctx.arc(midX - 12, midY, radius, 0, Math.PI * 2);
        ctx.arc(midX + 12, midY, radius, 0, Math.PI * 2);
        ctx.fill();
      } else if (count === 4) {
        // 2x2 grid
        for (var r = 0; r < 2; r++) {
          for (var c = 0; c < 2; c++) {
            ctx.beginPath();
            ctx.arc(midX - 12 + c * 24, midY - 12 + r * 24, radius, 0, Math.PI * 2);
            ctx.fill();
          }
        }
      } else if (count === 8) {
        // 2x4 grid
        for (var r = 0; r < 2; r++) {
          for (var c = 0; c < 4; c++) {
            ctx.beginPath();
            ctx.arc(midX - 36 + c * 24, midY - 12 + r * 24, radius, 0, Math.PI * 2);
            ctx.fill();
          }
        }
      } else if (count === 16) {
        // 4x4 grid
        for (var r = 0; r < 4; r++) {
          for (var c = 0; c < 4; c++) {
            ctx.beginPath();
            ctx.arc(midX - 36 + c * 24, midY - 36 + r * 24, radius, 0, Math.PI * 2);
            ctx.fill();
          }
        }
      }
    }

    // Draw based on stage
    if (stage === 1) {
      drawGrid(2, '#EF4444');
    } else if (stage === 2) {
      drawGrid(4, '#3B82F6');
    } else if (stage === 3) {
      drawGrid(8, '#10B981');
    } else {
      drawGrid(16, '#F59E0B');
    }

    // Bottom text explanations
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.font = 'bold 15px -apple-system, sans-serif';
    ctx.fillStyle = '#F3F4F6';

    if (stage === 1) {
      ctx.fillText('2¹ = 2', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('Base 2 is written 1 time.', W / 2, H - 22);
    } else if (stage === 2) {
      ctx.fillStyle = '#60A5FA';
      ctx.fillText('2² = 2 × 2 = 4', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('Base 2 is multiplied 2 times (2 squared).', W / 2, H - 22);
    } else if (stage === 3) {
      ctx.fillStyle = '#34D399';
      ctx.fillText('2³ = 2 × 2 × 2 = 8', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('Base 2 is multiplied 3 times (2 cubed).', W / 2, H - 22);
    } else {
      ctx.fillStyle = '#FBBF24';
      ctx.fillText('2⁴ = 2 × 2 × 2 × 2 = 16', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('Base 2 is multiplied 4 times. Notice the doubling pattern.', W / 2, H - 22);
    }
  }
};
